const topics = $input.first().json.output.topics;

let out = [];

for (const topic of topics) {
  for (const query of topic.queries) {
    out.push({
      topic: topic.topic,
      query: query
    });
  }
}

return out.map(i => ({ json: i }));

let out = [];

for (const item of items) {
    // Берём массив relevant_points
    const points = item.json.relevant_points;

    for (const p of points) {
        out.push({
            json: {
                topic: item.json.topic,
                query: item.json.query,
                chunk_id: p.id,
                score: p.score,
                preview_text: p.payload.text,
                source_file: p.payload.source_file
            }
        });
    }
}

return out;

// Вход: items — массив объектов, как у тебя
const aggregated = {};

// Проходим по всем входным items
for (const item of items) {
    const { topic, query, chunk_id, preview_text, source_file } = item.json;

    // Формируем ключ по topic + query
    const key = `${topic}||${query}`;

    if (!aggregated[key]) {
        aggregated[key] = {
            topic,
            query,
            chunk_id: new Set(),
            preview_text: new Set(),
            source_file: new Set()
        };
    }

    aggregated[key].chunk_id.add(chunk_id);
    aggregated[key].preview_text.add(preview_text);
    aggregated[key].source_file.add(source_file);
}

// Преобразуем Set в массивы и формируем результат для n8n
const output = Object.values(aggregated).map(entry => ({
    json: {
        topic: entry.topic,
        query: entry.query,
        chunk_id: Array.from(entry.chunk_id),
        preview_text: Array.from(entry.preview_text),
        source_file: Array.from(entry.source_file)
    }
}));

return output;;
